() => {
  const b=document.querySelector('.ml-hero__btn'); const cs=getComputedStyle(b);
  const hits=[]; const layers=[];
  const walk=(rules,src,layer)=>{ for(const r of rules){ const cn=r.constructor.name;
    if(cn==='CSSLayerBlockRule'){ const nm=(layer||'')+'>'+(r.name||'(anon)'); layers.push(nm+' @ '+((src||'').split('/').pop().split('?')[0])); try{walk(r.cssRules,src,nm);}catch(e){} continue; }
    if(r.type===4){ try{walk(r.cssRules,src,layer);}catch(e){} continue; }
    if(!r.selectorText) continue;
    if(r.selectorText.indexOf('ml-hero__btn')>=0){ hits.push({sel:r.selectorText.slice(0,150), css:r.cssText.slice(0,240), layer:layer||'(none)', src:(src||'').split('/').pop().split('?')[0]}); } } };
  for(const s of document.styleSheets){ let rs; try{rs=s.cssRules;}catch(e){ continue; } walk(rs, s.href||'inline',''); }
  return { computedBg: cs.backgroundColor, computedRadius: cs.borderRadius, inlineAttr: b.getAttribute('style'), layersFound: layers.slice(0,20), hits };
}
